#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,q,r[MAXN],m[MAXN],p[MAXN],f[MAXN],cnt=0;
vector<int> h[MAXN];
signed main(void)
{
	n=read(),q=read();
	FOR(i,1,n)
	{
		r[i]=read();
		if(r[i])
		{
			m[i]=1;
			p[++cnt]=i;
			if(!m[r[i]])
			{
				p[++cnt]=r[i];
			}
			m[r[i]]=1;
			h[r[i]].pb(i);
		}
	}
	sort(p+1,p+cnt+1);
	wh(q--)
	{
		int u=read(),v=read();
        int s=u,x=u;
		f[u]=0;
		ROF(k,cnt,1)
		{
			int i=p[k];
			if(i<v)break;
			if(i>u)continue;
			x=i;
			f[i]=f[s]+s-i;
			FOI(j,h[i])
			{
				if(j<=u)
				{
					f[i]=min(f[i],f[j]+1);
				}
			}
			if(f[i]<f[s]+s-i)s=i;
		}
		if(x==v)writeln(f[v]);
		else writeln(f[x]+x-v);
	}
	return false;
}
